external_knowledge:
- 'thriving literary figures' refers to authors with an active status;
- 'basic personal details' include name, surname, gender, and email;
- 'life stories' refers to biography text and awards;
- 'academic and professional history' covers education and professional background;
- 'genre of writing' refers to the genre name of books they have written;
- 'accolades they have received' includes the name of awards and the year awarded.

sql:
SELECT country, COUNT(DISTINCT author_id) AS unique_author_count
FROM authors
GROUP BY country;

SELECT DISTINCT a.name, a.nationality
FROM authors a
INNER JOIN awards aw ON a.author_id = aw.author_id;

SELECT a.name, a.surname, aw.award_name
FROM authors a
LEFT JOIN awards aw ON a.author_id = aw.author_id;

